(function executeRule(current, previous /*null when async*/ ) {

    // Add your code here

    // Initialize GlideRecord for the Workspace Option table
    var workspaceGr = new GlideRecord("x_1759267_wrm_workspace_options");

    if (workspaceGr.get("sys_id", current.workspace)) {
        // Update value to under_maintenance
        workspaceGr.status = "under_maintenance";
        workspaceGr.update();
        return;
    } else {
        gs.error("BR - Workspace Maintenance → Options (Open): Unable to get current workspace details to update value");
    }

